const historicalData = {
  interestRates: [0.5, 1.0, 1.5, 2.0, 2.5], // Example interest rates
  employmentRates: [4.5, 4.4, 4.3, 4.2, 4.1], // Corresponding employment rates
  inflation: [1.5, 1.4, 1.3, 1.2, 1.1], // Corresponding inflation rates
