// Function to calculate the impact of a 0.25% interest rate increase on various economic indicators
function simulateInterestRateImpact() {
  // Calculate the average change in economic indicators for each 0.25% increase in interest rates
  const interestRateChange = 0.25;
  let totalChangeInEmployment = 0;
  let totalChangeInInflation = 0;
  let totalChangeInStockMarket = 0;
  let totalChangeInGDP = 0;
  let numberOfChanges = 0;

