      numberOfChanges++;
    }
  }

  // Calculate the average change per 0.25% increase
  const averageChangeInEmployment = totalChangeInEmployment / numberOfChanges;
  const averageChangeInInflation = totalChangeInInflation / numberOfChanges;
  const averageChangeInStockMarket = totalChangeInStockMarket / numberOfChanges;
  const averageChangeInGDP = totalChangeInGDP / numberOfChanges;

