using Microsoft.ML;
using Microsoft.ML.Data;
using System;
using System.Collections.Generic;
using System.IO;

public class CustomerData
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public float SocialMediaScore { get; set; } // Feature extracted from social media data

    [LoadColumn(3)]
    public bool Label { get; set; } // 1 if the customer purchased the product, 0 otherwise
}

public class Prediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
}

class Program
{
    static void Main(string[] args)
    {
        // Initialize ML.NET context
        var mlContext = new MLContext(seed: 0);

        // Load the dataset
        var dataPath = "customer_data.csv";
        var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(path: dataPath, hasHeader: true);

        // Split the dataset into training and test sets
        var trainingData = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2).TrainSet;
        var testData = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2).TestSet;

        // Define the data processing pipeline
        var dataProcessPipeline = mlContext.Transforms.Conversion.MapValueToKey(outputColumnName: "Label", inputColumnName: "Label")
            .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "SocialMediaScore"))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"));

        // Define the trainer and add it to the pipeline
        var trainer = mlContext.BinaryClassification.Trainers.LogisticRegression();
        var trainingPipeline = dataProcessPipeline.Append(trainer)
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Train the model
        var model = trainingPipeline.Fit(trainingData);

        // Evaluate the model
        var predictions = model.Transform(testData);
        var metrics = mlContext.BinaryClassification.Evaluate(predictions);

        Console.WriteLine($"Accuracy: {metrics.Accuracy:P2}");
        Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:P2}");

        // Use the model to make predictions
        var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, Prediction>(model);
        var sampleData = new CustomerData
        {
            Age = 30,
            Income = 50000,
            SocialMediaScore = 0.75
        };

        var prediction = predictionEngine.Predict(sampleData);
        Console.WriteLine($"Predicted Label: {prediction.PredictedLabel}");
    }
}
```

