// Function to perform binary search
int binarySearch(const std::vector<std::string>& sortedData, const std::string& target) {
    int left = 0;
    int right = sortedData.size() - 1;

    while (left <= right) {
        int mid = left + (right - left) / 2;

        if (sortedData[mid] == target) {
            return mid; // Target found
        } else if (sortedData[mid] < target) {
            left = mid + 1; // Search in the right half
        } else {
            right = mid - 1; // Search in the left half
        }
    }

    return -1; // Target not found
}

int main() {
    // Step 1: Create and sort the dataset
    std::vector<std::string> data = {"apple", "banana", "cherry", "date", "fig", "grape"};
    std::sort(data.begin(), data.end());

    // Step 2: Perform binary search
    std::string target = "date";
    int result = binarySearch(data, target);

    if (result != -1) {
        std::cout << "Target found at index: " << result << std::endl;
    } else {
        std::cout << "Target not found" << std::endl;
    }

    return 0;
}
```

