Here's a Python program that simulates a priority stack:

```python
import sys

class PriorityQueue:
    def __init__(self):
        self.elements = []

    def is_empty(self):
        return len(self.elements) == 0

    def push(self, item, priority):
        self.elements.append((priority, item))

    def pop(self):
        if self.is_empty():
            raise IndexError("pop from an empty priority queue")
        self.elements.sort(key=lambda x: x[0], reverse=True)
        return self.elements.pop()[1]

    def peek(self):
        if self.is_empty():
            raise IndexError("peek from an empty priority queue")
        return self.elements[0][1]

    def size(self):
        return len(self.elements)

def main():
    pq = PriorityQueue()
    print("Priority Queue Operations")
    print("1. Push (Insert) an element")
    print("2. Pop (Remove) an element")
    print("3. Peek at the top element")
    print("4. Show size of the priority queue")
    print("5. Exit")

    while True:
        try:
            choice = int(input("Enter choice: "))
            if choice == 1:
                item = input("Enter item to insert: ")
                priority = int(input("Enter priority: "))
                pq.push(item, priority)
                print(f"Inserted {item} with priority {priority}")
            elif choice == 2:
                item = pq.pop()
                print(f"Popped {item}")
            elif choice == 3:
                item = pq.peek()
                print(f"Top element is {item}")
            elif choice == 4:
                size = pq.size()
                print(f"Size of priority queue is {size}")
            elif choice == 5:
                print("Exiting program.")
                sys.exit()
            else:
                print("Invalid choice. Please try again.")
        except ValueError:
            print("Invalid input. Please enter a valid number.")
        except IndexError as e:
            print(e)

if __name__ == "__main__":
    main()
```

